parameters.jsCode:
const b = $input.first().json.body || $input.first().json;
const required = ['client_name','slug','industry'];
for (const k of required) { if (!b[k]) throw new Error(`field required: ${k}`); }
const brand = b.brand_assets || {};
return [{ json: {
  task_id: `landing_${Date.now()}`,
  client_name: b.client_name,
  slug: b.slug,
  industry: b.industry,
  location: b.location || null,
  country: b.country || null,
  products: b.products || null,
  diferenciador: b.diferenciador || null,
  whatsapp: b.whatsapp || null,
  instagram_handle: b.instagram_handle || null,
  target_deliverable: b.target_deliverable || 'landing-v1',
  brand_assets: { logo_url: brand.logo_url || null, colors: brand.colors || brand.brand_colors || null, fonts: brand.fonts || brand.brand_fonts || null },
  scrape_summary: b.scrape_summary || null,
} }];

